export function t(
  key: string,
  replacements?: Record<string, string | number>,
): string {
  let s = translations[key] ?? key;
  if (!replacements) return s;
  for (const [k, v] of Object.entries(replacements)) {
    s = s.split(`{${k}}`).join(String(v));
  }
  return s;
}
